export type AspectRatio = '1:1' | '16:9' | '9:16' | '3:4' | '4:3';
export type ImageResolution = '1K' | '2K' | '4K';

export interface GenerationConfig {
  prompt: string;
  aspectRatio: AspectRatio;
  resolution: ImageResolution;
}

export interface GenerationResult {
  imageUrl: string | null;
  text?: string;
  loading: boolean;
  error: string | null;
}

export interface WindowAIStudio {
  hasSelectedApiKey: () => Promise<boolean>;
  openSelectKey: () => Promise<void>;
}

declare global {
  interface Window {
    aistudio: WindowAIStudio;
  }
}

import { GoogleGenAI } from "@google/genai";
import { AspectRatio, ImageResolution } from "../types";

// Default prompt provided by the user
export const DEFAULT_PROMPT = `Create an ultra-realistic premium logo for the brand "ConexTV".
The design should feature a modern metallic look with chromed silver and gold accents, glowing edges, and soft neon highlights.
Style: futuristic IPTV/tech brand, high-definition reflections, smooth gradients, vibrant energy flares.
The text "Conex" should be metallic silver with depth, and "TV" should be in gold with a strong 3D embossed effect.
Add a subtle wireless signal icon above the "V", integrated into the design.
Use high-contrast lighting, cinematic glow, soft backlight rim, and glossy contours.
Background: dark blurred stadium/tech atmosphere with light streaks, but keep the logo as the main focus.
Resolution: 8K, extremely sharp, no distortions, proportional spacing.
Style reference: the original logo attached (same overall concept but more modern, cleaner, and more premium).`;

export const checkApiKey = async (): Promise<boolean> => {
  if (window.aistudio) {
    return await window.aistudio.hasSelectedApiKey();
  }
  return false;
};

export const promptForApiKey = async (): Promise<void> => {
  if (window.aistudio) {
    await window.aistudio.openSelectKey();
  } else {
    console.error("AI Studio environment not detected.");
  }
};

export const generateImage = async (
  prompt: string,
  aspectRatio: AspectRatio,
  resolution: ImageResolution
): Promise<string> => {
  // Always create a new instance to ensure the latest API Key is used
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found. Please select a project.");
  }

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          {
            text: prompt,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
          imageSize: resolution,
        },
      },
    });

    let imageUrl = '';
    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      const parts = candidates[0].content.parts;
      for (const part of parts) {
        if (part.inlineData) {
          const base64EncodeString = part.inlineData.data;
          // Determine mimeType if available, defaulting to png if not explicitly returned in a way we can parse easily
          // The API usually returns proper mimeType in inlineData
          const mimeType = part.inlineData.mimeType || 'image/png';
          imageUrl = `data:${mimeType};base64,${base64EncodeString}`;
          break; // Found the image, stop searching
        }
      }
    }

    if (!imageUrl) {
      throw new Error("No image data found in response");
    }

    return imageUrl;

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    // Enhance error message if it's a permission issue or quota
    if (error.message && error.message.includes("403")) {
      throw new Error("Access denied. Please check your API key permissions and ensure the API is enabled.");
    }
    throw error;
  }
};

import React, { useEffect, useState } from 'react';
import { checkApiKey, promptForApiKey } from '../services/geminiService';
import { ArrowRight, Key } from 'lucide-react';

interface ApiKeyCheckerProps {
  onKeyValid: () => void;
}

const ApiKeyChecker: React.FC<ApiKeyCheckerProps> = ({ onKeyValid }) => {
  const [hasKey, setHasKey] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  const verifyKey = async () => {
    setIsLoading(true);
    try {
      const valid = await checkApiKey();
      setHasKey(valid);
      if (valid) {
        onKeyValid();
      }
    } catch (e) {
      console.error("Failed to check API key", e);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    verifyKey();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleConnect = async () => {
    try {
      await promptForApiKey();
      // Wait a moment for the selection to potentially propagate, then re-check
      // The guidelines say: "assume the key selection was successful... Do not add delay".
      // However, re-checking state is safer for React rendering flow.
      await verifyKey();
      // Force valid call just in case verify fails due to race condition, 
      // but only if we trust the user completed the flow.
      // For better UX, we'll rely on verifyKey returning true eventually or user clicking again.
      // But adhering to: "assume the key selection was successful... proceed to the app"
      onKeyValid(); 
    } catch (e) {
      console.error("Failed to select key", e);
    }
  };

  if (hasKey) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md">
      <div className="max-w-md w-full mx-4 p-8 rounded-2xl border border-zinc-800 bg-zinc-900 shadow-2xl text-center space-y-6">
        <div className="mx-auto w-16 h-16 rounded-full bg-yellow-500/10 flex items-center justify-center border border-yellow-500/20">
          <Key className="w-8 h-8 text-yellow-500" />
        </div>

        <div className="space-y-2">
          <h2 className="text-2xl font-bold text-white">Connect Google Cloud</h2>
          <p className="text-zinc-400 text-sm leading-relaxed">
            High-definition 4K generation requires a paid API key from a Google Cloud Project. 
          </p>
        </div>

        <button
          onClick={handleConnect}
          disabled={isLoading}
          className="w-full group relative inline-flex items-center justify-center px-6 py-3 text-base font-semibold text-zinc-950 transition-all duration-200 bg-gradient-to-r from-yellow-400 to-yellow-500 rounded-lg hover:from-yellow-300 hover:to-yellow-400 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-yellow-500 focus:ring-offset-zinc-900"
        >
          {isLoading ? 'Checking...' : 'Select Billing Project'}
          <ArrowRight className="ml-2 w-4 h-4 group-hover:translate-x-1 transition-transform" />
        </button>

        <p className="text-xs text-zinc-600">
          See <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="text-yellow-600 hover:text-yellow-500 underline">billing documentation</a> for details.
        </p>
      </div>
    </div>
  );
};

export default ApiKeyChecker;

import React from 'react';
import { Download, Maximize2, Loader2 } from 'lucide-react';

interface ImageDisplayProps {
  imageUrl: string | null;
  loading: boolean;
  error: string | null;
}

const ImageDisplay: React.FC<ImageDisplayProps> = ({ imageUrl, loading, error }) => {
  if (loading) {
    return (
      <div className="w-full aspect-square md:aspect-video rounded-2xl glass-panel border border-zinc-700/50 flex flex-col items-center justify-center text-center p-8 relative overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-yellow-500/5 to-purple-500/5 animate-pulse" />
        <Loader2 className="w-12 h-12 text-yellow-500 animate-spin mb-4 relative z-10" />
        <h3 className="text-lg font-medium text-white relative z-10">Crafting Masterpiece</h3>
        <p className="text-sm text-zinc-400 mt-2 max-w-xs relative z-10">
          Generating high-fidelity 4K assets. This may take a moment due to complex ray-tracing simulation...
        </p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="w-full aspect-video rounded-2xl glass-panel border border-red-500/20 flex flex-col items-center justify-center p-8 text-center bg-red-500/5">
        <div className="text-red-400 font-medium text-lg mb-2">Generation Failed</div>
        <p className="text-zinc-400 text-sm max-w-md">{error}</p>
      </div>
    );
  }

  if (!imageUrl) {
    return (
      <div className="w-full aspect-video rounded-2xl glass-panel border border-dashed border-zinc-700 flex flex-col items-center justify-center p-8 text-center opacity-60">
        <div className="w-16 h-16 rounded-full bg-zinc-800 mb-4 flex items-center justify-center">
          <Maximize2 className="w-6 h-6 text-zinc-500" />
        </div>
        <p className="text-zinc-400 text-sm">Preview area. Your generated image will appear here.</p>
      </div>
    );
  }

  return (
    <div className="group relative w-full rounded-2xl overflow-hidden shadow-2xl ring-1 ring-white/10 bg-black">
       {/* Background Blur for nicer framing if aspect ratio differs */}
      <div 
        className="absolute inset-0 bg-cover bg-center blur-2xl opacity-40 scale-110"
        style={{ backgroundImage: `url(${imageUrl})` }} 
      />

      <div className="relative z-10 w-full h-full flex items-center justify-center p-4">
        <img 
          src={imageUrl} 
          alt="Generated Logo" 
          className="max-h-[70vh] w-auto object-contain rounded-lg shadow-2xl"
        />
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black/90 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex justify-end items-center z-20">
        <a 
          href={imageUrl} 
          download={`conextv-logo-${Date.now()}.png`}
          className="flex items-center gap-2 px-5 py-2.5 bg-white text-black font-semibold rounded-full hover:bg-zinc-200 transition-colors shadow-lg"
        >
          <Download className="w-4 h-4" />
          Download Asset
        </a>
      </div>
    </div>
  );
};

export default ImageDisplay;

